class ParkingSystem {
public:
    ParkingSystem(int big, int medium, int small) {
        slots[0] = big;
        slots[1] = medium;
        slots[2] = small;
    }

    bool addCar(int carType) {
        if (--slots[carType - 1] >= 0) return true;
        return false;
    }
private:
    int slots[3];
};
